return [{json: {
  draftContent: content,
  draftTitle: title,
  wordCount,
  validated: true
}}];

const draft1 = $('Validate Draft 1').first().json;
const draft2 = $('Validate Draft 2').first().json;
const draft3 = $('Validate Draft 3').first().json;
const submission = $('Prepare Content Base').first().json;

const drafts = [
  {
    index: 1,
    angle: 'Contrarian / Challenge Assumptions',
    title: draft1.draftTitle,
    content: draft1.draftContent,
    wordCount: draft1.wordCount
  },
  {
    index: 2,
    angle: 'Practical How-To Guide',
    title: draft2.draftTitle,
    content: draft2.draftContent,
    wordCount: draft2.wordCount
  },
  {
    index: 3,
    angle: 'Data, Trends & Research',
    title: draft3.draftTitle,
    content: draft3.draftContent,
    wordCount: draft3.wordCount
  }
];

return [{json: {
  submissionId: submission.submissionId,
  drafts,
  generatedAt: new Date().toISOString()
}}];

const data = $('Package All Drafts').first().json;
return [{json: {
  statusCode: 200,
  body: {
    success: true,
    submissionId: data.submissionId,
    status: 'pending_review',
    drafts: data.drafts.map(d => ({
      index: d.index,
      angle: d.angle,
      title: d.title,
      preview: d.content.substring(0, 200) + '...',
      wordCount: d.wordCount
    })),
    message: 'Three drafts generated. Please review and select one to proceed.'
  }
}}];

const body = $input.first().json.body || $input.first().json;
const errors = [];

if (!body || typeof body !== 'object') {
  errors.push('Request body is required');
}

const submissionId = body?.submissionId?.toString().trim() || body?.submission_id?.toString().trim() || '';
const selectedDraft = parseInt(body?.selectedDraft || body?.selected_draft, 10);

if (!submissionId) {
  errors.push('submission_id is required');
}

if (![1, 2, 3].includes(selectedDraft)) {
  errors.push('selected_draft must be 1, 2, or 3');
}

if (errors.length > 0) {
  return [{json: {error: true, statusCode: 400, message: errors.join('; ')}}];
}

return [{json: {
  error: false,
  submissionId,
  selectedDraft,
  publishImmediately: body?.publishImmediately === true || body?.publish_immediately === true
}}];

const results = $input.first().json;
const selectionInput = $('Validate Selection Input').first().json;

// Handle array response from Supabase
const submissions = Array.isArray(results) ? results : [results];

if (!submissions || submissions.length === 0 || !submissions[0].id) {
  return [{json: {error: true, statusCode: 404, message: 'Submission not found'}}];
}

const submission = submissions[0];

// Check status
if (submission.status !== 'pending_review') {
  return [{json: {error: true, statusCode: 409, message: `Submission is in '${submission.status}' state. Only 'pending_review' submissions can be selected.`}}];
}

// Check expiry (72 hours)
const createdAt = new Date(submission.created_at || submission.createdAt);
const now = new Date();
const hoursSinceCreation = (now - createdAt) / (1000 * 60 * 60);

if (hoursSinceCreation > 72) {
  return [{json: {error: true, statusCode: 410, message: 'Submission has expired. Drafts are only valid for 72 hours. Please create a new submission.'}}];
}

return [{json: {
  error: false,
  submission,
  submissionId: selectionInput.submissionId,
  selectedDraft: selectionInput.selectedDraft,
  publishImmediately: selectionInput.publishImmediately
}}];

const state = $('Validate Submission State').first().json;
const submission = state.submission;
const selectedIndex = state.selectedDraft;

let drafts = submission.drafts;
if (typeof drafts === 'string') {
  try {
    drafts = JSON.parse(drafts);
  } catch(e) {
    return [{json: {error: true, message: 'Could not parse stored drafts'}}];
  }
}

if (!Array.isArray(drafts) || drafts.length === 0) {
  return [{json: {error: true, message: 'No drafts found in submission'}}];
}

const selected = drafts.find(d => d.index === selectedIndex);
if (!selected) {
  return [{json: {error: true, message: `Draft ${selectedIndex} not found. Available: ${drafts.map(d => d.index).join(', ')}`}}];
}

return [{json: {
  submissionId: state.submissionId,
  selectedDraft: selectedIndex,
  draftTitle: selected.title,
  draftContent: selected.content,
  draftAngle: selected.angle,
  draftWordCount: selected.wordCount,
  publishImmediately: state.publishImmediately
}}];

const input = $input.first().json;
let content = '';
try {
  content = input.choices[0].message.content.trim();
} catch(e) {
  return [{json: {error: true, message: 'AI returned empty LinkedIn adaptation'}}];
}

// Strip ALL markdown — LinkedIn is plain text only
content = content.replace(/\*\*([^*]+)\*\*/g, '$1');
content = content.replace(/\*([^*]+)\*/g, '$1');
content = content.replace(/__([^_]+)__/g, '$1');
content = content.replace(/_([^_]+)_/g, '$1');
content = content.replace(/^#{1,6}\s+/gm, '');
content = content.replace(/^[-*]\s+/gm, '\u2022 ');
content = content.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');
content = content.replace(/\n*(?:#\w+\s*)+$/g, '');

if (content.length > 3000) {
  content = content.substring(0, 2997) + '...';
}

const hasCTA = /\?|comment|share|follow|what do you think|thoughts/i.test(content);

return [{json: {
  linkedinContent: content,
  charCount: content.length,
  hasCTA,
  truncated: content.length >= 3000
}}];

const input = $input.first().json;
let content = '';
try {
  content = input.choices[0].message.content.trim();
} catch(e) {
  content = '';
}

if (!content) {
  return [{json: {error: true, message: 'AI returned empty X/Twitter adaptation'}}];
}

if (content.length <= 280) {
  return [{json: {twitterContent: content, charCount: content.length, truncated: false}}];
}

// Try to truncate at last sentence boundary under 280
const sentences = content.match(/[^.!?]+[.!?]+/g) || [content];
let truncated = '';
for (const sentence of sentences) {
  if ((truncated + sentence).length <= 280) {
    truncated += sentence;
  } else {
    break;
  }
}

if (truncated.length > 0 && truncated.length <= 280) {
  return [{json: {twitterContent: truncated.trim(), charCount: truncated.trim().length, truncated: true}}];
}

// Fallback: hard cut at 277 + ...
const hardCut = content.substring(0, 277) + '...';
return [{json: {twitterContent: hardCut, charCount: 280, truncated: true}}];

const input = $input.first().json;
let content = '';
try {
  content = input.choices[0].message.content.trim();
} catch(e) {
  return [{json: {error: true, message: 'AI returned empty newsletter adaptation'}}];
}

let subject = 'New from Fetemi';
const subjectMatch = content.match(/^SUBJECT:\s*(.+)$/mi);
if (subjectMatch) {
  subject = subjectMatch[1].trim();
  content = content.replace(/^SUBJECT:\s*.+$/mi, '').trim();
}

// Strip any HTML/body wrapper tags the AI added
content = content.replace(/<\/?html[^>]*>/gi, '');
content = content.replace(/<\/?body[^>]*>/gi, '');
content = content.replace(/<\/?head[^>]*>/gi, '');
content = content.replace(/<\/?doctype[^>]*>/gi, '');

// If AI output HTML, use it directly. If markdown, convert.
const hasHTML = /<(?:p|h[1-6]|ul|ol|div|strong|em|a\s)[^>]*>/i.test(content);

if (!hasHTML) {
  // Convert markdown to HTML
  content = content
    .replace(/### (.+)/g, '<h3>$1</h3>')
    .replace(/## (.+)/g, '<h2>$1</h2>')
    .replace(/# (.+)/g, '<h2>$1</h2>')
    .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
    .replace(/\*([^*]+)\*/g, '<em>$1</em>')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');

  // Convert bullet lists
  const lines = content.split('\n');
  let result = [];
  let inList = false;
  for (const line of lines) {
    const trimmed = line.trim();
    if (/^[-*]\s+/.test(trimmed)) {
      if (!inList) { result.push('<ul>'); inList = true; }
      result.push('<li>' + trimmed.replace(/^[-*]\s+/, '') + '</li>');
    } else {
      if (inList) { result.push('</ul>'); inList = false; }
      if (!trimmed) continue;
      if (trimmed.startsWith('<')) {
        result.push(trimmed);
      } else {
        result.push('<p>' + trimmed + '</p>');
      }
    }
  }
  if (inList) result.push('</ul>');
  content = result.join('\n');
}

// Clean up any double-wrapped paragraphs
content = content.replace(/<p>\s*<p>/g, '<p>');
content = content.replace(/<\/p>\s*<\/p>/g, '</p>');

const htmlContent = '<div style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif;max-width:600px;margin:0 auto;color:#333;line-height:1.6;font-size:16px;">' +
  content +
  '<hr style="border:none;border-top:1px solid #eee;margin:24px 0;">' +
  '<p style="color:#888;font-size:13px;">Sent by Fetemi Marketing</p></div>';

const wordCount = content.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().split(' ').length;

return [{json: {
  newsletterSubject: subject,
  newsletterContent: htmlContent,
  newsletterWordCount: wordCount,
  withinRange: wordCount >= 200 && wordCount <= 700
}}];

const linkedin = $('Validate LinkedIn Content').first().json;
const twitter = $('Enforce X Character Limit').first().json;
const newsletter = $('Validate Newsletter Content').first().json;
const draft = $('Extract Selected Draft').first().json;

const idempotencyKey = draft.submissionId + '_' + draft.selectedDraft + '_' + Date.now().toString(36);

return [{json: {
  submissionId: draft.submissionId,
  selectedDraft: draft.selectedDraft,
  draftTitle: draft.draftTitle,
  draftAngle: draft.draftAngle,
  publishImmediately: draft.publishImmediately,
  idempotencyKey,
  adaptations: {
    linkedin: {
      content: linkedin.linkedinContent,
      charCount: linkedin.charCount,
      hasCTA: linkedin.hasCTA
    },
    twitter: {
      content: twitter.twitterContent,
      charCount: twitter.charCount,
      truncated: twitter.truncated
    },
    newsletter: {
      subject: newsletter.newsletterSubject,
      content: newsletter.newsletterContent,
      wordCount: newsletter.newsletterWordCount || 0
    }
  },
  adaptedAt: new Date().toISOString()
}}];

