const publishData = $('Prepare Publishing Data').first().json;

// Collect results from all paths
const results = [];
const platformsPublished = [];
const errors = [];

// Helper to safely get a result from a node
function getResult(nodeName) {
  try {
    return $(nodeName).first().json;
  } catch(e) {
    return null;
  }
}

// LinkedIn result
