  published_at: results.publishedAt,
  message: results.success
    ? 'Content published to: ' + results.platformsPublished.join(', ')
    : 'Publishing failed for all platforms. See errors for details.'
} }];

// Pure JavaScript HMAC-SHA1 for OAuth 1.0a (no crypto module needed)
function sha1Bytes(bytes) {
  function rotl(n, s) { return (n << s) | (n >>> (32 - s)); }
  var i, W = new Array(80);
  var H0 = 0x67452301, H1 = 0xEFCDAB89, H2 = 0x98BADCFE, H3 = 0x10325476, H4 = 0xC3D2E1F0;
  var A, B, C, D, E, temp;
  var msgBytes = bytes.slice();
  var msgLen = msgBytes.length;
  msgBytes.push(0x80);
  while (msgBytes.length % 64 !== 56) { msgBytes.push(0); }
  var bitLen = msgLen * 8;
  msgBytes.push(0, 0, 0, 0);
  msgBytes.push((bitLen >>> 24) & 0xff, (bitLen >>> 16) & 0xff, (bitLen >>> 8) & 0xff, bitLen & 0xff);
  for (var blockstart = 0; blockstart < msgBytes.length; blockstart += 64) {
    for (i = 0; i < 16; i++) {
      W[i] = (msgBytes[blockstart + i * 4] << 24) | (msgBytes[blockstart + i * 4 + 1] << 16) | (msgBytes[blockstart + i * 4 + 2] << 8) | msgBytes[blockstart + i * 4 + 3];
    }
    for (i = 16; i < 80; i++) { W[i] = rotl(W[i - 3] ^ W[i - 8] ^ W[i - 14] ^ W[i - 16], 1); }
    A = H0; B = H1; C = H2; D = H3; E = H4;
    for (i = 0; i < 80; i++) {
      if (i < 20) { temp = (rotl(A, 5) + ((B & C) | (~B & D)) + E + W[i] + 0x5A827999) & 0xffffffff; }
      else if (i < 40) { temp = (rotl(A, 5) + (B ^ C ^ D) + E + W[i] + 0x6ED9EBA1) & 0xffffffff; }
      else if (i < 60) { temp = (rotl(A, 5) + ((B & C) | (B & D) | (C & D)) + E + W[i] + 0x8F1BBCDC) & 0xffffffff; }
      else { temp = (rotl(A, 5) + (B ^ C ^ D) + E + W[i] + 0xCA62C1D6) & 0xffffffff; }
      E = D; D = C; C = rotl(B, 30); B = A; A = temp;
    }
    H0 = (H0 + A) & 0xffffffff; H1 = (H1 + B) & 0xffffffff;
    H2 = (H2 + C) & 0xffffffff; H3 = (H3 + D) & 0xffffffff; H4 = (H4 + E) & 0xffffffff;
  }
  var result = [];
  [H0, H1, H2, H3, H4].forEach(function(h) {
    result.push((h >>> 24) & 0xff, (h >>> 16) & 0xff, (h >>> 8) & 0xff, h & 0xff);
  });
  return result;
}

function strToBytes(str) {
  var bytes = [];
  for (var i = 0; i < str.length; i++) { bytes.push(str.charCodeAt(i) & 0xff); }
  return bytes;
}

function bytesToBase64(bytes) {
  var chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
  var result = '';
  for (var i = 0; i < bytes.length; i += 3) {
    var b1 = bytes[i], b2 = bytes[i + 1] || 0, b3 = bytes[i + 2] || 0;
    var triplet = (b1 << 16) | (b2 << 8) | b3;
    result += chars[(triplet >>> 18) & 0x3f];
    result += chars[(triplet >>> 12) & 0x3f];
    result += (i + 1 < bytes.length) ? chars[(triplet >>> 6) & 0x3f] : '=';
    result += (i + 2 < bytes.length) ? chars[triplet & 0x3f] : '=';
  }
  return result;
}

function hmacSha1(key, message) {
  var keyBytes = strToBytes(key);
  var msgBytes = strToBytes(message);
  if (keyBytes.length > 64) { keyBytes = sha1Bytes(keyBytes); }
  while (keyBytes.length < 64) { keyBytes.push(0); }
  var oKeyPad = keyBytes.map(function(b) { return b ^ 0x5c; });
  var iKeyPad = keyBytes.map(function(b) { return b ^ 0x36; });
  var innerHash = sha1Bytes(iKeyPad.concat(msgBytes));
  return bytesToBase64(sha1Bytes(oKeyPad.concat(innerHash)));
}

function generateNonce() {
  var chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  var nonce = '';
  for (var i = 0; i < 32; i++) { nonce += chars.charAt(Math.floor(Math.random() * chars.length)); }
  return nonce;
}

// Get credentials from Prepare Publishing Data
const data = $('Prepare Publishing Data').first().json;
const config = data.twitterConfig;
const consumerKey = config.consumer_key;
const consumerSecret = config.consumer_secret;
const accessToken = data.twitterAccessToken;
const accessTokenSecret = config.access_token_secret;

const method = 'POST';
const url = 'https://api.twitter.com/2/tweets';
const tweetText = data.adapted.twitterContent;

// Generate OAuth parameters
const timestamp = Math.floor(Date.now() / 1000).toString();
const nonce = generateNonce();

const oauthParams = {
  oauth_consumer_key: consumerKey,
  oauth_nonce: nonce,
  oauth_signature_method: 'HMAC-SHA1',
  oauth_timestamp: timestamp,
  oauth_token: accessToken,
  oauth_version: '1.0'
};

// Create signature base string
const paramString = Object.keys(oauthParams)
  .sort()
  .map(key => encodeURIComponent(key) + '=' + encodeURIComponent(oauthParams[key]))
  .join('&');

const signatureBase = method.toUpperCase() + '&' + 
  encodeURIComponent(url) + '&' + 
  encodeURIComponent(paramString);

const signingKey = encodeURIComponent(consumerSecret) + '&' + encodeURIComponent(accessTokenSecret);

const signature = hmacSha1(signingKey, signatureBase);

// Build Authorization header
const authHeader = 'OAuth ' + Object.keys(oauthParams)
  .sort()
  .map(key => encodeURIComponent(key) + '="' + encodeURIComponent(oauthParams[key]) + '"')
  .concat('oauth_signature="' + encodeURIComponent(signature) + '"')
  .join(', ');

return [{ json: {
  ...data,
  twitterAuthHeader: authHeader,
  tweetBody: JSON.stringify({ text: tweetText })
} }];

const connections = $input.first().json;
const connArray = Array.isArray(connections) ? connections : [connections];
const connMap = {};
for (const c of connArray) {
  if (c && c.platform) connMap[c.platform] = c;
}

const adapted = $('Combine Adapted Content').first().json;

const linkedin = connMap.linkedin || {};
const newsletter = connMap.newsletter || {};
const nlConfig = newsletter.config || {};

return [{ json: {
  linkedinAccessToken: linkedin.access_token || '',
  linkedinUserId: linkedin.platform_user_id || '',
  publishLinkedin: !!(linkedin.access_token),
  newsletterApiKey: newsletter.api_key || '',
  newsletterFrom: nlConfig.from_address || nlConfig.sender_email || 'onboarding@resend.dev',
  newsletterFromName: nlConfig.sender_name || 'Fetemi Marketing',
  publishNewsletter: !!(newsletter.api_key),
  adaptations: adapted.adaptations || {},
  idempotencyKey: adapted.idempotencyKey || ''
} }];

const body = $input.first().json.body || $input.first().json;
const errors = [];

if (!body || typeof body !== 'object') {
  errors.push('Request body is required');
}

const rawIdea = body?.rawIdea?.toString().trim() || '';
const url = body?.url?.toString().trim() || '';

if (!rawIdea && !url) {
  errors.push('Either rawIdea or url must be provided');
}

if (url && !/^https?:\/\/.+\..+/.test(url)) {
  errors.push('url must be a valid HTTP/HTTPS URL');
}

if (rawIdea && rawIdea.length > 10000) {
  errors.push('rawIdea must be under 10,000 characters');
}

const payloadSize = JSON.stringify(body).length;
if (payloadSize > 1048576) {
  errors.push('Payload exceeds 1MB size limit');
}

// Sanitize inputs
const sanitized = {
  rawIdea: rawIdea.replace(/<[^>]*>/g, '').substring(0, 10000),
  url: url,
  publishImmediately: body?.publishImmediately === true,
};

if (errors.length > 0) {
  return [{json: {error: true, statusCode: 400, message: errors.join('; ')}}];
}

return [{json: {error: false, ...sanitized}}];

const input = $input.first().json;
const content = input.rawIdea || input.url;

// Simple hash function
let hash = 0;
for (let i = 0; i < content.length; i++) {
  const char = content.charCodeAt(i);
  hash = ((hash << 5) - hash) + char;
  hash = hash & hash;
}
const contentHash = Math.abs(hash).toString(36);

const submissionId = 'sub_' + Date.now().toString(36) + '_' + Math.random().toString(36).substring(2, 8);
const tenMinAgo = new Date(Date.now() - 10 * 60 * 1000).toISOString();

return [{json: {
  ...input,
  submissionId,
  contentHash,
  tenMinAgo,
  createdAt: new Date().toISOString()
}}];

const input = $input.first().json;
const url = $('Generate Submission ID & Dedup Hash').first().json.url || '';

let html = '';
if (typeof input === 'string') html = input;
else if (input.data) html = input.data;
else if (input.body) html = input.body;
else html = JSON.stringify(input);

const isYouTube = /(?:youtube\.com\/watch|youtu\.be\/|youtube\.com\/shorts\/)/.test(url);
const isInstagram = /instagram\.com\/(?:p|reel|tv)\//.test(url);

// === YOUTUBE: get transcript via local transcript service ===
if (isYouTube) {
  let videoTitle = '';
  const titleMatch = html.match(/<meta\s+name="title"\s+content="([^"]+)"/i)
    || html.match(/"title":"([^"]+)"/);
  if (titleMatch) videoTitle = titleMatch[1];

  // Call the transcript service
  let transcript = '';
  try {
    const transcriptResp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'http://127.0.0.1:3456/?url=' + encodeURIComponent(url),
      returnFullResponse: false,
      timeout: 30000
    });

    const tData = typeof transcriptResp === 'string' ? JSON.parse(transcriptResp) : transcriptResp;
    transcript = tData.transcript || '';
    if (tData.title && !videoTitle) videoTitle = tData.title;
  } catch(e) {
    // Transcript service unavailable — fall back to description
  }

  // Fallback to description if transcript empty
  if (!transcript) {
    const descMatch = html.match(/"shortDescription":"((?:[^"\\]|\\.)*)"/);
    if (descMatch) transcript = descMatch[1].replace(/\\n/g, '\n');
  }

  if (!transcript || transcript.length < 30) {
    return [{json: {error: true, message: 'Could not extract transcript from YouTube video. No captions available.'}}];
  }

  const isTranscript = transcript.length > 200;
  const label = isTranscript ? 'YouTube Video Transcript' : 'YouTube Video Description';
  let text = `[Source: ${label}]\nTitle: ${videoTitle}\n\n${transcript}`;
  if (text.length > 8000) text = text.substring(0, 8000);
  return [{json: {extractedContent: text, charCount: text.length, title: videoTitle, inputType: 'url'}}];
}

// === INSTAGRAM ===
if (isInstagram) {
  let caption = '';
  const metaMatch = html.match(/<meta[^>]+content="([^"]+)"[^>]+property="og:description"/i)
    || html.match(/<meta[^>]+property="og:description"[^>]+content="([^"]+)"/i);
  if (metaMatch) caption = metaMatch[1];
  let title = '';
  const ogTitle = html.match(/<meta[^>]+property="og:title"[^>]+content="([^"]+)"/i);
  if (ogTitle) title = ogTitle[1];
  if (!caption || caption.length < 10) {
    return [{json: {error: true, message: 'Could not extract content from Instagram post.'}}];
  }
  let text = `[Source: Instagram]\nTitle: ${title}\n\n${caption}`;
  if (text.length > 5000) text = text.substring(0, 5000);
  return [{json: {extractedContent: text, charCount: text.length, title: title, inputType: 'url'}}];
}

// === REGULAR WEBPAGE — SMART ARTICLE EXTRACTION ===
let title = '';
const ogTitleMatch = html.match(/<meta[^>]+property="og:title"[^>]+content="([^"]+)"/i)
  || html.match(/<meta[^>]+content="([^"]+)"[^>]+property="og:title"/i);
if (ogTitleMatch) title = ogTitleMatch[1].trim();
if (!title) {
  const pageTitleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (pageTitleMatch) title = pageTitleMatch[1].trim();
}

let ogDesc = '';
const ogDescMatch = html.match(/<meta[^>]+property="og:description"[^>]+content="([^"]+)"/i)
  || html.match(/<meta[^>]+content="([^"]+)"[^>]+property="og:description"/i)
  || html.match(/<meta[^>]+name="description"[^>]+content="([^"]+)"/i);
if (ogDescMatch) ogDesc = ogDescMatch[1].trim();

html = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
html = html.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
html = html.replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '');
html = html.replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '');
html = html.replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '');
html = html.replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, '');
html = html.replace(/<noscript[^>]*>[\s\S]*?<\/noscript>/gi, '');
html = html.replace(/<iframe[^>]*>[\s\S]*?<\/iframe>/gi, '');
html = html.replace(/<svg[^>]*>[\s\S]*?<\/svg>/gi, '');
html = html.replace(/<form[^>]*>[\s\S]*?<\/form>/gi, '');
html = html.replace(/<button[^>]*>[\s\S]*?<\/button>/gi, '');
html = html.replace(/<input[^>]*>/gi, '');
html = html.replace(/<select[^>]*>[\s\S]*?<\/select>/gi, '');

function cleanHtml(h) {
  let t = h.replace(/<[^>]+>/g, ' ');
  t = t.replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>')
    .replace(/&nbsp;/g,' ').replace(/&quot;/g,'"').replace(/&#39;/g,"'")
    .replace(/&#\d+;/g,'').replace(/&\w+;/g,'');
  return t.replace(/\s+/g, ' ').trim();
}

let articleContent = '';
const articleMatch = html.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
if (articleMatch) articleContent = cleanHtml(articleMatch[1]);

let mainContent = '';
if (!articleContent || articleContent.length < 200) {
  const mainMatch = html.match(/<main[^>]*>([\s\S]*?)<\/main>/i);
  if (mainMatch) mainContent = cleanHtml(mainMatch[1]);
}

let roleContent = '';
if (!articleContent && !mainContent) {
  const roleMatch = html.match(/<div[^>]+role="main"[^>]*>([\s\S]*?)<\/div>/i)
    || html.match(/<div[^>]+class="[^"]*(?:post-content|article-content|entry-content|blog-content|post-body|article-body|content-body|single-post|story-body)[^"]*"[^>]*>([\s\S]*?)<\/div>/i);
  if (roleMatch) roleContent = cleanHtml(roleMatch[1] || roleMatch[2]);
}

let bestSection = '';
if (!articleContent && !mainContent && !roleContent) {
  const sections = html.split(/<div[^>]*>/i);
  let maxP = 0;
  for (const section of sections) {
    const pCount = (section.match(/<p[\s>]/gi) || []).length;
    const cleaned = cleanHtml(section);
    if (pCount > maxP && cleaned.length > 200) {
      maxP = pCount;
      bestSection = cleaned;
    }
  }
}

let text = articleContent || mainContent || roleContent || bestSection;
if (!text || text.length < 100) text = cleanHtml(html);

text = text.replace(/Sign up|Sign in|Log in|Subscribe|Newsletter|Cookie|Accept all|Reject all|Privacy Policy|Terms of Service|©\s*\d{4}/gi, '');
text = text.replace(/Share on \w+|Share this|Tweet this|Pin it|Email this/gi, '');
text = text.replace(/Read more|Load more|Show more|See all|View all/gi, '');
text = text.replace(/\d+ min read|\d+ minute read/gi, '');
text = text.replace(/\s+/g, ' ').trim();

if (title && !text.startsWith(title)) text = title + '\n\n' + text;
if (text.length > 5000) text = text.substring(0, 5000);

if (text.length < 50) {
  if (ogDesc && ogDesc.length >= 30) {
    text = title + '\n\n' + ogDesc;
  } else {
    return [{json: {error: true, message: 'Could not extract article content from URL.'}}];
  }
}

return [{json: {extractedContent: text, charCount: text.length, title: title, inputType: 'url'}}];

const prev = $('Generate Submission ID & Dedup Hash').first().json;
return [{json: {
  ...prev,
  contentBase: prev.rawIdea,
  inputType: 'raw_idea'
}}];

