const adapted = $('Combine Adapted Content').first().json;

const linkedinResult = $('S2: Publish to LinkedIn').first().json;
const twitterResult = $('Publish to X').first().json;
const newsletterResult = $('Send Newsletter').first().json;

return [{json: {
  submissionId: adapted.submissionId,
  status: 'published',
  publishedAt: new Date().toISOString(),
  results: {
    linkedin: {
      published: true,
      charCount: adapted.adaptations.linkedin.charCount,
      response: linkedinResult
    },
    twitter: {
      published: true,
      charCount: adapted.adaptations.twitter.charCount,
      response: twitterResult
    },
    newsletter: {
      sent: true,
      subject: adapted.adaptations.newsletter.subject,
      wordCount: adapted.adaptations.newsletter.wordCount,
      response: newsletterResult
    }
  },
  message: 'Content published to all platforms successfully.'
}}];

const adapted = $('Combine Adapted Content').first().json;

return [{json: {
  submissionId: adapted.submissionId,
  status: 'scheduled',
  adaptedAt: adapted.adaptedAt,
  adaptations: {
    linkedin: {
      preview: adapted.adaptations.linkedin.content.substring(0, 200) + '...',
      charCount: adapted.adaptations.linkedin.charCount
    },
    twitter: {
      preview: adapted.adaptations.twitter.content,
      charCount: adapted.adaptations.twitter.charCount
    },
    newsletter: {
      subject: adapted.adaptations.newsletter.subject,
      preview: adapted.adaptations.newsletter.content.substring(0, 200) + '...',
      wordCount: adapted.adaptations.newsletter.wordCount
    }
  },
  message: 'Content adapted for all platforms and saved. Ready for manual publishing or scheduling.'
}}];

const body = $input.first().json.body || $input.first().json;
const errors = [];

if (!body || typeof body !== 'object') {
  errors.push('Request body is required');
}

const submissionId = (body?.submission_id || body?.submissionId || '').toString().trim();
let platforms = body?.platforms || ['linkedin', 'twitter', 'newsletter'];

if (!submissionId) {
  errors.push('submission_id is required');
}

if (!Array.isArray(platforms)) {
  platforms = [platforms];
}

const validPlatforms = ['linkedin', 'twitter', 'newsletter'];
const invalidPlatforms = platforms.filter(p => !validPlatforms.includes(p));
if (invalidPlatforms.length > 0) {
  errors.push('Invalid platforms: ' + invalidPlatforms.join(', ') + '. Valid: linkedin, twitter, newsletter');
}

if (errors.length > 0) {
  return [{ json: { error: true, statusCode: 400, message: errors.join('; ') } }];
}

const idempotencyBase = submissionId + '_pub_' + Date.now().toString(36);

return [{ json: {
  error: false,
  submissionId,
  platforms,
  idempotencyBase
} }];

const adaptedRaw = $('Fetch Adapted Content').first().json;
const connectionsRaw = $('Fetch Platform Connections').all().map(i => i.json);
const publishInput = $('Validate Publish Input').first().json;

// Parse adapted content - Supabase returns array
const adaptedArr = Array.isArray(adaptedRaw) ? adaptedRaw : [adaptedRaw];
const adapted = adaptedArr[0] || adaptedRaw;

// Parse connections - flatten if nested arrays
let connections = [];
for (const item of connectionsRaw) {
  if (Array.isArray(item)) {
    connections.push(...item);
  } else {
    connections.push(item);
  }
}

const connectionMap = {};
for (const conn of connections) {
  if (conn && conn.platform) {
    connectionMap[conn.platform] = conn;
  }
}

const requestedPlatforms = publishInput.platforms || ['twitter', 'newsletter'];
const readyPlatforms = [];
const missingPlatforms = [];

for (const p of requestedPlatforms) {
  const conn = connectionMap[p];
  if (p === 'newsletter' && conn && (conn.api_key || conn.access_token)) {
    readyPlatforms.push('newsletter');
  } else if (conn && conn.access_token) {
    const expiresAt = conn.token_expires_at ? new Date(conn.token_expires_at) : null;
    if (expiresAt && expiresAt < new Date()) {
      missingPlatforms.push(p + ' (token expired)');
    } else {
      readyPlatforms.push(p);
    }
  } else {
    missingPlatforms.push(p + ' (not connected or missing token)');
  }
}

// Get newsletter config
const nlConn = connectionMap.newsletter || {};
const nlConfig = nlConn.config || {};

return [{ json: {
  submissionId: publishInput.submissionId,
  idempotencyBase: publishInput.idempotencyBase || publishInput.submissionId + '_' + Date.now(),
  adapted: {
    linkedinContent: adapted.linkedin_content || '',
    twitterContent: adapted.twitter_content || '',
    newsletterSubject: adapted.newsletter_subject || '',
    newsletterContent: adapted.newsletter_content || ''
  },
  connections: connectionMap,
  newsletterApiKey: nlConn.api_key || '',
  newsletterFromEmail: nlConfig.sender_email || 'content@fetemi.com',
  newsletterFromName: nlConfig.sender_name || 'Fetemi Marketing',
  twitterAccessToken: connectionMap.twitter ? connectionMap.twitter.access_token : '',
  twitterConfig: connectionMap.twitter ? (connectionMap.twitter.config || {}) : {},
  linkedinAccessToken: connectionMap.linkedin ? connectionMap.linkedin.access_token : '',
  linkedinUserId: connectionMap.linkedin ? connectionMap.linkedin.platform_user_id : '',
  readyPlatforms,
  missingPlatforms,
  publishLinkedin: readyPlatforms.includes('linkedin'),
  publishTwitter: readyPlatforms.includes('twitter'),
  publishNewsletter: readyPlatforms.includes('newsletter')
} }];

const response = $input.first().json;
const isError = !!response.error || !!response.errorMessage || (response.status && response.status >= 400);

if (isError) {
  return [{ json: {
    platform: 'linkedin',
    success: false,
    error: response.message || response.errorMessage || response.error || JSON.stringify(response)
